10.20.2 Population-Level Prior and Posterior Predictive Checks
Just as we did for the single-agent models, we want to visualize what our multilevel models believe before seeing the data, and what they learned after.
Since we will have to run our slower multilevel code through e.g.SBC, we kept the generated quantities leaner than usual: we didn’t include population-level prior or posterior predictions in the generated quantities blocks (though we kept trial-level posterior predictions for existing agents via pred_choice). Instead, we can simulate these hierarchical, population-level predictions dynamically in R. This is an essential skill: by drawing from our population hyper-priors (\(\mu\) and \(\sigma\)), sampling new individual agents, and pushing those through the Beta-Binomial observation model, we can perfectly reconstruct the model’s population-level expectations.

# 1. Custom function to simulate Multilevel Prior/Posterior Predictions in R
generate_ml_ppc &lt;- function(model_name, fit, data_df, is_prior = FALSE, n_draws = 400) {
  # Prep data
  obs_df &lt;- data_df |&gt; 
    mutate(obs_id = row_number()) |&gt;
    select(obs_id, agent_id, blue1, total1, blue2, total2, choice)

  # Create base grid of draws x observations
  base_grid &lt;- expand_grid(.draw = 1:n_draws, obs_id = obs_df$obs_id) |&gt;
    left_join(obs_df, by = "obs_id")

  if (model_name == "ML-SBA") {
    # SBA has no parameters, prior and posterior are identical
    pred_samples &lt;- base_grid |&gt;
      mutate(
        alpha_p = 0.5 + blue1 + blue2,
        beta_p  = 0.5 + (total1 - blue1) + (total2 - blue2),
        theta   = rbeta(n(), alpha_p, beta_p),
        pred    = rbinom(n(), 1, theta)
      )

  } else if (model_name == "ML-PBA") {
    if (is_prior) {
      pred_samples &lt;- base_grid |&gt;
        group_by(.draw) |&gt;
        mutate(mu_p = rnorm(1, 0, 1.5), sig_p = rexp(1, 2)) |&gt;
        group_by(.draw, agent_id) |&gt;
        mutate(p_j = plogis(mu_p + sig_p * rnorm(1))) |&gt;
        ungroup() |&gt;
        mutate(
          alpha_p = 0.5 + p_j * blue1 + (1 - p_j) * blue2,
          beta_p  = 0.5 + p_j * (total1 - blue1) + (1 - p_j) * (total2 - blue2),
          theta   = rbeta(n(), alpha_p, beta_p),
          pred    = rbinom(n(), 1, theta)
        )
    } else {
      draws &lt;- as_draws_df(fit$draws("p")) |&gt; 
        sample_n(n_draws, replace = TRUE) |&gt; mutate(.draw = row_number()) |&gt;
        select(.draw, starts_with("p[")) |&gt; 
        pivot_longer(-.draw, names_to = "param", values_to = "p_j") |&gt;
        mutate(agent_id = readr::parse_number(param)) |&gt; select(-param)

      pred_samples &lt;- base_grid |&gt; left_join(draws, by = c(".draw", "agent_id")) |&gt;
        mutate(
          alpha_p = 0.5 + p_j * blue1 + (1 - p_j) * blue2,
          beta_p  = 0.5 + p_j * (total1 - blue1) + (1 - p_j) * (total2 - blue2),
          theta   = rbeta(n(), alpha_p, beta_p),
          pred    = rbinom(n(), 1, theta)
        )
    }

  } else if (model_name == "ML-WBA") {
    if (is_prior) {
      pred_samples &lt;- base_grid |&gt;
        group_by(.draw) |&gt;
        mutate(
          mu_1 = rnorm(1, 0, 1.5), mu_2 = rnorm(1, log(2), 0.5),
          sig_1 = rexp(1, 2), sig_2 = rexp(1, 2),
          omega = 2 * rbeta(1, 2, 2) - 1,
          L21 = omega, L22 = sqrt(1 - omega^2)
        ) |&gt;
        group_by(.draw, agent_id) |&gt;
        mutate(
          z1 = rnorm(1), z2 = rnorm(1),
          rho_j = plogis(mu_1 + sig_1 * z1),
          kappa_j = exp(mu_2 + sig_2 * (L21 * z1 + L22 * z2)),
          wd_j = rho_j * kappa_j, ws_j = (1 - rho_j) * kappa_j
        ) |&gt;
        ungroup() |&gt;
        mutate(
          alpha_p = 0.5 + wd_j * blue1 + ws_j * blue2,
          beta_p  = 0.5 + wd_j * (total1 - blue1) + ws_j * (total2 - blue2),
          theta   = rbeta(n(), alpha_p, beta_p),
          pred    = rbinom(n(), 1, theta)
        )
    } else {
      draws &lt;- as_draws_df(fit$draws(c("weight_direct", "weight_social"))) |&gt;
        sample_n(n_draws, replace = TRUE) |&gt; mutate(.draw = row_number()) |&gt;
        select(.draw, starts_with("weight_")) |&gt;
        pivot_longer(-.draw, names_to = "param", values_to = "val") |&gt;
        mutate(
          agent_id = readr::parse_number(param), 
          param_type = str_extract(param, "weight_[a-z]+")
        ) |&gt;
        select(-param) |&gt; pivot_wider(names_from = param_type, values_from = val)

      pred_samples &lt;- base_grid |&gt; left_join(draws, by = c(".draw", "agent_id")) |&gt;
        mutate(
          alpha_p = 0.5 + weight_direct * blue1 + weight_social * blue2,
          beta_p  = 0.5 + weight_direct * (total1 - blue1) + weight_social * (total2 - blue2),
          theta   = rbeta(n(), alpha_p, beta_p),
          pred    = rbinom(n(), 1, theta)
        )
    }
  }

  # Summarize (Averaging over all agents to get population-level PPC)
  obs_summary &lt;- obs_df |&gt; group_by(blue1, blue2) |&gt; summarise(p_obs = mean(choice), .groups = "drop")

  pred_summary &lt;- pred_samples |&gt;
    group_by(.draw, blue1, blue2) |&gt; summarise(p_draw = mean(pred), .groups = "drop") |&gt;
    group_by(blue1, blue2) |&gt;
    summarise(
      p_pred = median(p_draw), 
      lower = quantile(p_draw, 0.025), 
      upper = quantile(p_draw, 0.975), 
      .groups = "drop"
    ) |&gt;
    left_join(obs_summary, by = c("blue1", "blue2")) |&gt;
    mutate(
      social_evidence = factor(blue2, levels = 0:3, labels = c("Clear Red", "Maybe Red", "Maybe Blue", "Clear Blue")),
      Scenario = ifelse(is_prior, paste(model_name, "- Prior"), paste(model_name, "- Posterior"))
    )

  return(pred_summary)
}

