10.27.7 Simulation-Based Calibration (SBC): Pinpointing the Source of Complexity
With our three models written natively in Stan, we face a significant computational challenge. The jardri_f transformation is highly non-linear. Furthermore, the loop parameters (\(\alpha\)) multiply the evidence before it passes through this transformation, and the interference model creates feedback loops between the two sources.
When parameters interact multiplicatively inside non-linear bounds, identifiability issues are almost guaranteed. To see exactly where these problems emerge, we will run Simulation-Based Calibration (SBC) on all three models in our pedagogical sequence: 1. Weights Only 2. Weights + Loops 3. Full Interference
We will simulate datasets from the priors of each model, fit the corresponding Stan model to them, and compare their calibration and parameter recovery side-by-side.

# Ensure all models are compiled
mod_ci_weights      &lt;- cmdstan_model("stan/ch9_ci_weights_only.stan", dir = "simmodels")
mod_ci_loops        &lt;- cmdstan_model("stan/ch9_ci_loops.stan", dir = "simmodels")
mod_ci_interference &lt;- cmdstan_model("stan/ch9_ci_interference.stan", dir = "simmodels")

if (regenerate_simulations || !file.exists("simmodels/ch9_sbc_ci_all_results.rds")) {

  # 1. Define the R equivalent of the Jardri function for the generators
  jardri_f &lt;- function(L, w) {
    num &lt;- w * exp(L) + (1.0 - w)
    den &lt;- (1.0 - w) * exp(L) + w
    return(log(num / den))
  }

  # Helper to sample from truncated normal [0.5, 1.0] for weights
  draw_w &lt;- function() {
    w &lt;- -1
    while(w &lt; 0.5 || w &gt; 1.0) w &lt;- rnorm(1, 0.75, 0.25)
    return(w)
  }

  N_sbc_trials &lt;- nrow(evidence_combinations) * 5 # 180 trials per simulated agent

  # --- GENERATOR 1: Weights Only ---
  sbc_gen_weights &lt;- SBC_generator_function(
    function(N) {
      ws &lt;- draw_w()
      wo &lt;- draw_w()
      ev &lt;- evidence_combinations |&gt; slice_sample(n = N, replace = TRUE)

      lo_s &lt;- log((0.5 + ev$blue1) / (0.5 + ev$total1 - ev$blue1))
      lo_o &lt;- log((0.5 + ev$blue2) / (0.5 + ev$total2 - ev$blue2))

      L_post &lt;- jardri_f(lo_s, ws) + jardri_f(lo_o, wo)
      choices &lt;- rbinom(N, 1, plogis(L_post))

      list(
        variables = list(w_self = ws, w_other = wo),
        generated = list(N = N, choice = choices, blue1 = ev$blue1, 
                         total1 = ev$total1, blue2 = ev$blue2, total2 = ev$total2)
      )
    }, N = N_sbc_trials
  )

  # --- GENERATOR 2: Weights + Loops ---
  sbc_gen_loops &lt;- SBC_generator_function(
    function(N) {
      ws &lt;- draw_w()
      wo &lt;- draw_w()
      as_m1 &lt;- abs(rnorm(1, 0, 1)); ao_m1 &lt;- abs(rnorm(1, 0, 1))
      as_ &lt;- 1.0 + as_m1; ao_ &lt;- 1.0 + ao_m1

      ev &lt;- evidence_combinations |&gt; slice_sample(n = N, replace = TRUE)
      lo_s &lt;- log((0.5 + ev$blue1) / (0.5 + ev$total1 - ev$blue1))
      lo_o &lt;- log((0.5 + ev$blue2) / (0.5 + ev$total2 - ev$blue2))

      L_post &lt;- jardri_f(as_ * lo_s, ws) + jardri_f(ao_ * lo_o, wo)
      choices &lt;- rbinom(N, 1, plogis(L_post))

      list(
        variables = list(w_self = ws, w_other = wo, alpha_self_m1 = as_m1, alpha_other_m1 = ao_m1),
        generated = list(N = N, choice = choices, blue1 = ev$blue1, 
                         total1 = ev$total1, blue2 = ev$blue2, total2 = ev$total2)
      )
    }, N = N_sbc_trials
  )

  # --- GENERATOR 3: Full Interference ---
  sbc_gen_interference &lt;- SBC_generator_function(
    function(N) {
      ws &lt;- draw_w()
      wo &lt;- draw_w()
      as_m1 &lt;- abs(rnorm(1, 0, 1)); ao_m1 &lt;- abs(rnorm(1, 0, 1))
      as_ &lt;- 1.0 + as_m1; ao_ &lt;- 1.0 + ao_m1

      ev &lt;- evidence_combinations |&gt; slice_sample(n = N, replace = TRUE)
      lo_s &lt;- log((0.5 + ev$blue1) / (0.5 + ev$total1 - ev$blue1))
      lo_o &lt;- log((0.5 + ev$blue2) / (0.5 + ev$total2 - ev$blue2))

      I &lt;- jardri_f(as_ * lo_s, ws) + jardri_f(ao_ * lo_o, wo)
      L_post &lt;- jardri_f(lo_s + I, ws) + jardri_f(lo_o + I, wo)
      choices &lt;- rbinom(N, 1, plogis(L_post))

      list(
        variables = list(w_self = ws, w_other = wo, alpha_self_m1 = as_m1, alpha_other_m1 = ao_m1),
        generated = list(N = N, choice = choices, blue1 = ev$blue1, 
                         total1 = ev$total1, blue2 = ev$blue2, total2 = ev$total2)
      )
    }, N = N_sbc_trials
  )

  # 2. Generate datasets
  n_sbc &lt;- 400
  datasets_weights &lt;- generate_datasets(sbc_gen_weights, n_sbc)
  datasets_loops   &lt;- generate_datasets(sbc_gen_loops, n_sbc)
  datasets_interf  &lt;- generate_datasets(sbc_gen_interference, n_sbc)

  # 3. Setup Backends
  sampler_args &lt;- list(chains = 2, iter_warmup = 500, iter_sampling = 500, parallel_chains = 2, refresh = 0)

  backend_weights &lt;- do.call(SBC::SBC_backend_cmdstan_sample, c(list(model = mod_ci_weights), sampler_args))
  backend_loops   &lt;- do.call(SBC::SBC_backend_cmdstan_sample, c(list(model = mod_ci_loops), sampler_args))
  backend_interf  &lt;- do.call(SBC::SBC_backend_cmdstan_sample, c(list(model = mod_ci_interference), sampler_args))

  # 4. Compute SBC
  sbc_res_weights &lt;- compute_SBC(datasets_weights, backend_weights, keep_fits = FALSE)
  sbc_res_loops   &lt;- compute_SBC(datasets_loops, backend_loops, keep_fits = FALSE)
  sbc_res_interf  &lt;- compute_SBC(datasets_interf, backend_interf, keep_fits = FALSE)

  saveRDS(list(weights = sbc_res_weights, loops = sbc_res_loops, interf = sbc_res_interf), 
          "simmodels/ch9_sbc_ci_all_results.rds")

} else {
  sbc_all &lt;- readRDS("simmodels/ch9_sbc_ci_all_results.rds")
  sbc_res_weights &lt;- sbc_all$weights
  sbc_res_loops   &lt;- sbc_all$loops
  sbc_res_interf  &lt;- sbc_all$interf
}


